@prefix sh: <http://www.w3.org/ns/shacl#> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

[] a sh:ValidationReport ;
    sh:conforms true .

@prefix rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#> .
@prefix schema1: <http://schema.org/> .
@prefix sh: <http://www.w3.org/ns/shacl#> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode [ a schema1:PropertyValue ;
                    schema1:description "Surface air temperature measurements" ;
                    schema1:name "Temperature" ] ;
            sh:resultMessage "a propertID must be a uri reference, a name string, or a schema:DefinedTerm" ;
            sh:resultPath schema1:propertyID ;
            sh:resultSeverity sh:Warning ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape [ sh:message "a propertID must be a uri reference, a name string, or a schema:DefinedTerm" ;
                    sh:minCount 1 ;
                    sh:or ( [ sh:nodeKind sh:IRI ] [ sh:datatype xsd:string ;
                                sh:minLength 5 ] [ sh:class schema1:DefinedTerm ;
                                sh:property [ sh:message "a defined term should have an identifier that is a resolvable URI" ;
                                        sh:minCount 1 ;
                                        sh:or ( [ ] [ ] [ ] ) ;
                                        sh:path schema1:identifier ] ] ) ;
                    sh:path schema1:propertyID ;
                    sh:severity sh:Warning ] ] .

